package gohistogram

import (
	"testing"
)

func TestTrim(t *testing.T) {
	// Test case 1: Simple case where bins need to be merged once
	t.Run("SimpleMerge", func(t *testing.T) {
		h := NewHistogram(3)
		h.bins = []bin{
			{value: 10, count: 1},
			{value: 20, count: 1},
			{value: 30, count: 1},
			{value: 40, count: 1},
		}
		h.total = 4

		h.trim()

		if len(h.bins) != 3 {
			t.Errorf("Expected 3 bins after trim, got %d", len(h.bins))
		}

		// The two closest bins (by value) should be merged
		found := false
		for _, b := range h.bins {
			// In this case, the closest bins are 10 and 20, so we should have a merged bin with
			// value = (10*1 + 20*1)/(1+1) = 15 and count = 2
			if b.value == 15 && b.count == 2 {
				found = true
				break
			}
		}
		if !found {
			t.Errorf("Expected merged bin with value 15 and count 2, not found in %v", h.bins)
		}
	})

	// Test case 2: Multiple merges required
	t.Run("MultipleMerges", func(t *testing.T) {
		h := NewHistogram(2)
		h.bins = []bin{
			{value: 10, count: 1},
			{value: 20, count: 1},
			{value: 30, count: 1},
			{value: 40, count: 1},
		}
		h.total = 4

		h.trim()

		if len(h.bins) != 2 {
			t.Errorf("Expected 2 bins after trim, got %d", len(h.bins))
		}

		// There should be two merges, resulting in two bins
		// First merge: closest bins (10,20) -> new bin with value 15, count 2
		// Second merge: either (15,30) or (30,40) depending on which has smaller delta
		// Delta between 15 and 30 is 15, delta between 30 and 40 is 10
		// So (30,40) should be merged -> new bin with value 35, count 2
		foundFirst := false
		foundSecond := false
		for _, b := range h.bins {
			if b.value == 15 && b.count == 2 {
				foundFirst = true
			}
			if b.value == 35 && b.count == 2 {
				foundSecond = true
			}
		}
		if !foundFirst || !foundSecond {
			t.Errorf("Expected bins with values 15 (count 2) and 35 (count 2), got %v", h.bins)
		}
	})

	// Test case 3: Test with weighted values
	t.Run("WeightedValues", func(t *testing.T) {
		h := NewHistogram(2)
		h.bins = []bin{
			{value: 10, count: 2},  // weight of 2
			{value: 20, count: 3},  // weight of 3
			{value: 100, count: 1}, // weight of 1
		}
		h.total = 6

		h.trim()

		if len(h.bins) != 2 {
			t.Errorf("Expected 2 bins after trim, got %d", len(h.bins))
		}

		// The closest bins are 10 and 20 (delta = 10)
		// Merged bin value: (10*2 + 20*3)/(2+3) = 16
		// Merged bin count: 2 + 3 = 5
		foundMerged := false
		foundUnchanged := false
		for _, b := range h.bins {
			if b.value == 16 && b.count == 5 {
				foundMerged = true
			}
			if b.value == 100 && b.count == 1 {
				foundUnchanged = true
			}
		}
		if !foundMerged || !foundUnchanged {
			t.Errorf("Expected bins with values 16 (count 5) and 100 (count 1), got %v", h.bins)
		}
	})

	// Test case 4: Edge case with bins already at or below maxbins
	t.Run("NoMergeNeeded", func(t *testing.T) {
		h := NewHistogram(3)
		h.bins = []bin{
			{value: 10, count: 1},
			{value: 20, count: 1},
			{value: 30, count: 1},
		}
		h.total = 3

		originalBins := make([]bin, len(h.bins))
		copy(originalBins, h.bins)

		h.trim()

		if len(h.bins) != 3 {
			t.Errorf("Expected 3 bins after trim, got %d", len(h.bins))
		}

		// No merge should happen, bins should remain unchanged
		for i, b := range h.bins {
			if b.value != originalBins[i].value || b.count != originalBins[i].count {
				t.Errorf("Expected unchanged bin at index %d, got %v", i, b)
			}
		}
	})
}

