impl NumericHistogram {
    pub(crate) fn trim(&mut self) -> Result<()> {
        while self.bins.len() > self.maxbins {
            let mut min_delta = f64::INFINITY;
            let mut min_delta_index = 0;
            for i in 1..self.bins.len() {
                let delta = self.bins[i].value - self.bins[i - 1].value;
                if delta < min_delta {
                    min_delta = delta;
                    min_delta_index = i;
                }
            }
            let total_count = self.bins[min_delta_index - 1].count
                + self.bins[min_delta_index].count;
            let merged_bin = Bin {
                value: (self.bins[min_delta_index - 1].value
                    * self.bins[min_delta_index - 1].count
                    + self.bins[min_delta_index].value
                        * self.bins[min_delta_index].count) / total_count,
                count: total_count,
            };

            // Create new bins collection with correct ordering
            let mut new_bins = VecDeque::new();

            // Add all bins before min_delta_index-1
            for i in 0..min_delta_index-1 {
                new_bins.push_back(self.bins[i].clone());
            }

            // Add merged bin
            new_bins.push_back(merged_bin);

            // Add all bins after min_delta_index
            for i in min_delta_index+1..self.bins.len() {
                new_bins.push_back(self.bins[i].clone());
            }

            // Replace bins with new collection
            self.bins = new_bins;
        }
        Ok(())
    }

