                let i_copy = i;
                let _ = trim_result; // Use trim_result at the end
                self.scale_down(i_copy);
                return;
            }
        }

        self.bins.push(Bin { value: n, count: 1.0 });
        // No need for additional operations when appending to the end
        let _ = trim_result; // Use trim_result at the end
    }
