pub fn quantile(&self, q: f64) -> Result<f64, anyhow::Error> {
    let count = q * self.total;
    let mut remaining_count = count;
    for bin in &self.bins {
        remaining_count -= bin.count;
        if remaining_count <= 0.0 {
            return Ok(bin.value);
        }
    }
    Err(anyhow!("No quantile found"))
}

