			wantTotal: 0,
		},
		{
			name:      "large bin count test",
			n:         1000,
			alpha:     0.05,
			wantBins:  0,
			wantTotal: 0,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			h := NewWeightedHistogram(tt.n, tt.alpha)

			// Check that the initial properties are set correctly
			if len(h.bins) != tt.wantBins {
				t.Errorf("NewWeightedHistogram() bins = %v, want %v", len(h.bins), tt.wantBins)
			}
			if h.maxbins != tt.n {
				t.Errorf("NewWeightedHistogram() maxbins = %v, want %v", h.maxbins, tt.n)
			}
			if h.total != tt.wantTotal {
				t.Errorf("NewWeightedHistogram() total = %v, want %v", h.total, tt.wantTotal)
			}
			if h.alpha != tt.alpha {
				t.Errorf("NewWeightedHistogram() alpha = %v, want %v", h.alpha, tt.alpha)
			}

			// Skip adding values for zero bins test to avoid panic
			if tt.n == 0 {
				return
			}

			// Test functionality by adding some values
			h.Add(1.0)
